import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-24","description":"","frontmatter":{"title":"The Decoder — 2026-05-24","date":"2026-05-24T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-24-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-24-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-24-the-decoder.md"};function n(i,e,l,h,c,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🔓-the-decoder-—-2026-05-24" tabindex="-1">🔓 The Decoder — 2026-05-24 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-24" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-24&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="deepseek-makes-its-75-percent-discount-permanent-pricing-output-tokens-at-least-34x-below-gpt-5-5" tabindex="-1"><a href="https://the-decoder.com/deepseek-makes-its-75-percent-discount-permanent-pricing-output-tokens-at-least-34x-below-gpt-5-5/" target="_blank" rel="noreferrer">Deepseek makes its 75 percent discount permanent, pricing output tokens at least 34x below GPT-5.5</a> <a class="header-anchor" href="#deepseek-makes-its-75-percent-discount-permanent-pricing-output-tokens-at-least-34x-below-gpt-5-5" aria-label="Permalink to &quot;[Deepseek makes its 75 percent discount permanent, pricing output tokens at least 34x below GPT-5.5](https://the-decoder.com/deepseek-makes-its-75-percent-discount-permanent-pricing-output-tokens-at-least-34x-below-gpt-5-5/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-23</em></p><p>Deepseek is making the 75 percent discount on its top model V4-Pro permanent. At $0.435 per million input tokens, it&#39;s at least 11.5 times cheaper than GPT-5.5 and over 34 times cheaper on output. For token-hungry agentic systems, this kind of pricing could squeeze Western providers hard.</p><p>The article <a href="https://the-decoder.com/deepseek-makes-its-75-percent-discount-permanent-pricing-output-tokens-at-least-34x-below-gpt-5-5/" target="_blank" rel="noreferrer">Deepseek makes its 75 percent discount permanent, pricing output tokens at least 34x below GPT-5.5</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="one-of-the-world-s-top-law-schools-draws-a-hard-line-against-ai-in-legal-education" tabindex="-1"><a href="https://the-decoder.com/one-of-the-worlds-top-law-schools-draws-a-hard-line-against-ai-in-legal-education/" target="_blank" rel="noreferrer">One of the world&#39;s top law schools draws a hard line against AI in legal education</a> <a class="header-anchor" href="#one-of-the-world-s-top-law-schools-draws-a-hard-line-against-ai-in-legal-education" aria-label="Permalink to &quot;[One of the world&#39;s top law schools draws a hard line against AI in legal education](https://the-decoder.com/one-of-the-worlds-top-law-schools-draws-a-hard-line-against-ai-in-legal-education/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-23</em></p><p>UC Berkeley Law will ban AI from nearly all graded work starting in summer 2026, from outlining and drafting to proofreading. Only research use remains allowed. The school’s rationale: future lawyers must first learn to think for themselves before they can use AI meaningfully.</p><p>The article <a href="https://the-decoder.com/one-of-the-worlds-top-law-schools-draws-a-hard-line-against-ai-in-legal-education/" target="_blank" rel="noreferrer">One of the world&#39;s top law schools draws a hard line against AI in legal education</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="alibaba-s-latest-ai-model-ran-autonomously-for-35-hours-to-optimize-code-for-its-own-custom-chip" tabindex="-1"><a href="https://the-decoder.com/alibabas-latest-ai-model-ran-autonomously-for-35-hours-to-optimize-code-for-its-own-custom-chip/" target="_blank" rel="noreferrer">Alibaba&#39;s latest AI model ran autonomously for 35 hours to optimize code for its own custom chip</a> <a class="header-anchor" href="#alibaba-s-latest-ai-model-ran-autonomously-for-35-hours-to-optimize-code-for-its-own-custom-chip" aria-label="Permalink to &quot;[Alibaba&#39;s latest AI model ran autonomously for 35 hours to optimize code for its own custom chip](https://the-decoder.com/alibabas-latest-ai-model-ran-autonomously-for-35-hours-to-optimize-code-for-its-own-custom-chip/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-23</em></p><p>Alibaba&#39;s Qwen team releases Qwen3.7-Max, a proprietary model built for long-running autonomous agent tasks. It matches Claude Opus 4.6 on benchmarks and beats Chinese rivals like DeepSeek V4 Pro and Kimi K2.6. The team also demos the model steering a four-legged robot.</p><p>The article <a href="https://the-decoder.com/alibabas-latest-ai-model-ran-autonomously-for-35-hours-to-optimize-code-for-its-own-custom-chip/" target="_blank" rel="noreferrer">Alibaba&#39;s latest AI model ran autonomously for 35 hours to optimize code for its own custom chip</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-ceo-pichai-now-calls-links-a-part-of-search-redefining-the-web-s-role-in-its-own-product" tabindex="-1"><a href="https://the-decoder.com/google-ceo-pichai-now-calls-links-a-part-of-search-redefining-the-webs-role-in-its-own-product/" target="_blank" rel="noreferrer">Google CEO Pichai now calls links a &quot;part&quot; of search, redefining the web&#39;s role in its own product</a> <a class="header-anchor" href="#google-ceo-pichai-now-calls-links-a-part-of-search-redefining-the-web-s-role-in-its-own-product" aria-label="Permalink to &quot;[Google CEO Pichai now calls links a &quot;part&quot; of search, redefining the web&#39;s role in its own product](https://the-decoder.com/google-ceo-pichai-now-calls-links-a-part-of-search-redefining-the-webs-role-in-its-own-product/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-23</em></p><p>Google CEO Sundar Pichai now calls links and sources a &quot;part&quot; of search, when in reality, they&#39;re its foundation. The wording is deliberate: new features keep users inside the Google ecosystem, and the company is shifting from traffic distributor to AI publisher whose source selection is becoming a question of editorial power.</p><p>The article <a href="https://the-decoder.com/google-ceo-pichai-now-calls-links-a-part-of-search-redefining-the-webs-role-in-its-own-product/" target="_blank" rel="noreferrer">Google CEO Pichai now calls links a &quot;part&quot; of search, redefining the web&#39;s role in its own product</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-warns-claude-mythos-preview-finds-bugs-faster-than-developers-can-patch-them" tabindex="-1"><a href="https://the-decoder.com/anthropic-warns-claude-mythos-preview-finds-bugs-faster-than-developers-can-patch-them/" target="_blank" rel="noreferrer">Anthropic warns Claude Mythos Preview finds bugs faster than developers can patch them</a> <a class="header-anchor" href="#anthropic-warns-claude-mythos-preview-finds-bugs-faster-than-developers-can-patch-them" aria-label="Permalink to &quot;[Anthropic warns Claude Mythos Preview finds bugs faster than developers can patch them](https://the-decoder.com/anthropic-warns-claude-mythos-preview-finds-bugs-faster-than-developers-can-patch-them/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-23</em></p><p>Anthropic&#39;s AI model Claude Mythos Preview, working with about 50 partners as part of Project Glasswing, has found over 10,000 critical vulnerabilities in system-critical software. The bugs are piling up faster than anyone can patch them. Anthropic warns this creates a high-risk transition period and says no company, itself included, has built safeguards strong enough to prevent misuse of these models.</p><p>The article <a href="https://the-decoder.com/anthropic-warns-claude-mythos-preview-finds-bugs-faster-than-developers-can-patch-them/" target="_blank" rel="noreferrer">Anthropic warns Claude Mythos Preview finds bugs faster than developers can patch them</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
